script:
// Row color highlighting + Recalculate Month button
frappe.listview_settings['Employee Shift'] = {
    refresh(listview) {
        listview.wrapper.find('.list-row').each(function() {
            const row = $(this);
            const indicator = row.find('.indicator-pill').text().trim();
            if (indicator === 'Anomaly' || indicator.includes('Break punch')) {
                row.css('background-color', '#ffe6e6');
            } else if (indicator === 'Missing Check-Out' || indicator.includes('Unpaired')) {
                row.css('background-color', '#fff4e6');
            } else if (indicator === 'Paired') {
                row.css('background-color', '#e6f9ed');
            } else if (indicator === 'Manual') {
                row.css('background-color', '#e6eef9');
            }
        });
    }
};
